module accu
(
    input clk,
    input rst_n,
    input [7:0] data_in,
    input valid_in,
    output valid_out,
    output [9:0] data_out
);

reg [1:0] state, next_state;
reg [3:0] count;
reg [9:0] sum;
always @(posedge clk or negedge rst_n) begin
    if (!rst_n) state <= 2'd0;
    else state <= next_state;
end
always @(*) begin
    if (state == 2'd0) begin
        if (valid_in) next_state = 2'd1;
        else next_state = 2'd0;
    end
    else if (state == 2'd1) begin
        if (count == 4'd4 && !valid_in) next_state = 2'd2;
        else next_state = 2'd1;
    end
    else if (state == 2'd2) begin
        if (valid_out) next_state = 2'd0;
        else next_state = 2'd2;
    end
    else next_state = 2'd0;
end
always @(posedge clk or negedge rst_n) begin
    if (!rst_n) count <= 4'd0;
    else if (state == 2'd1) begin
        if (count == 4'd4 && !valid_in) count <= 4'd0;
        else if (valid_in) count <= count + 1'd1;
        else count <= count;
    end
    else count <= count;
end
always @(posedge clk or negedge rst_n) begin
    if (!rst_n) sum <= 10'd0;
    else if (state == 2'd1) begin
        if (count == 4'd4 && !valid_in) sum <= 10'd0;
        else if (valid_in) sum <= sum + data_in;
        else sum <= sum;
    end
    else if (state == 2'd0 && valid_in) sum <= data_in;
    else sum <= sum;
end
assign data_out = sum;
assign valid_out = (state == 2'd2);
endmodule
